const res = $input.first().json;
// Grok /v1/responses format: data.output[] with type='message' containing content[].output_text
const output = res.output || [];
let jsonText = '';
for (const o of output) {
  if (o.type === 'message' && Array.isArray(o.content)) {
    for (const c of o.content) {
      if (c.type === 'output_text' && c.text) { jsonText = c.text; break; }
    }
  }
  if (jsonText) break;
}

if (!jsonText) return [{ json: { skip: true, reason: 'no text from Grok' } }];

jsonText = jsonText.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();
const jm = jsonText.match(/\{[\s\S]*\}/);
if (jm) jsonText = jm[0];

let parsed;
try { parsed = JSON.parse(jsonText); } catch(e) { return [{ json: { skip: true, reason: 'parse error' } }]; }

const posts = parsed.posts || [];
const searchedCount = parsed.searched_count || 0;
if (!posts.length) return [{ json: { skip: true, reason: 'empty posts' } }];

const store = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);
store.lastChelDigest = today;

const styleRef = $('Prep Research Body').first().json.styleRef || '';

return [{ json: { posts, searchedCount, styleRef, skip: false, today } }];

const res = $input.first().json;
let post = '';
// AWstore (OpenAI-compatible) returns choices[0].message.content
if (res.choices && res.choices[0]?.message?.content) {
  post = res.choices[0].message.content.trim();
} else if (res.content && Array.isArray(res.content)) {
  const textBlock = res.content.find(c => c.type === 'text');
  post = textBlock?.text?.trim() || '';
}
post = post.replace(/@che_v_che\s*$/i, '').trim();
post += '\n\n@che_v_che';
const id = 'chel_' + Date.now() + '_' + Math.random().toString(36).slice(2,7);
return [{ json: { post, id } }];
